// Extract email body, subject, and arrival timestamp
const email = items[0].json;
const subject = email.subject || '';
const arrivalTs = email.date || new Date().toISOString();

// Get plain text body — prefer text/plain, fallback to stripping HTML
let body = '';
if (email.text) {
  body = email.text;
} else if (email.textHtml) {
  body = email.textHtml.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
} else if (email.snippet) {
  body = email.snippet;
}

if (!body || body.trim().length < 50) {
  throw new Error(`PARSE_FAIL: Email body too short or empty. Subject: ${subject}, Arrival: ${arrivalTs}`);
}

return [{ json: { body, subject, arrivalTs } }];

// Extract the fenced ```json STRUCTURED DATA block ChatGPT now emits directly in
// the email (see the updated scheduled-prompt), and JSON.parse it. No AI call is
// needed here anymore — ChatGPT already produced schema-shaped JSON upstream.
// Keep this logic in sync with assets/js/lib/extract-json.js (n8n Function nodes
// cannot `import` repo files, so this is a byte-equivalent inline copy).
const { body, subject, arrivalTs } = items[0].json;

function extractFirstBalancedObject(text) {
  const start = text.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escaped = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === '"') inString = false;
      continue;
    }
    if (ch === '"') { inString = true; continue; }
    if (ch === '{') depth++;
    else if (ch === '}') { depth--; if (depth === 0) return text.slice(start, i + 1); }
  }
  return null;
}

function extractJsonBlock(rawText) {
  if (typeof rawText !== 'string') return null;
  const fenced = rawText.match(/```json\s*([\s\S]*?)```/i);
  if (fenced) return fenced[1].trim();
  return extractFirstBalancedObject(rawText);
}

const jsonText = extractJsonBlock(body);
if (!jsonText) {
  return [{ json: { valid: false, error: 'PARSE_FAIL', message: 'No JSON block found in email body', subject, arrivalTs } }];
}

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  return [{ json: { valid: false, error: 'PARSE_FAIL', message: e.message, subject, arrivalTs } }];
}

return [{ json: { parsed, subject, arrivalTs } }];

// Validate the extracted briefing against the Per-Day JSON Schema (v1 + v2 fields).
// Keep the structural checks here in sync with assets/js/lib/schema.js's
// validateBriefing/normalizeBriefing (n8n Function nodes cannot import that file).
const input = items[0].json;
const { subject, arrivalTs } = input;

// Pass through an upstream extraction failure unchanged.
if (input.valid === false) return [{ json: input }];

const parsed = input.parsed;
const { meta, summary, triggers, deep_dive, outlook, prediction_result } = parsed || {};

if (!meta?.date || !/^\d{4}-\d{2}-\d{2}$/.test(meta.date)) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'meta.date missing or invalid', subject, arrivalTs } }];
}
if (!['Trading','Holiday'].includes(meta.session_status)) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'meta.session_status invalid', subject, arrivalTs } }];
}
if (!summary || !triggers || !deep_dive || !outlook || !prediction_result) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'Missing top-level keys', subject, arrivalTs } }];
}
if (!Array.isArray(outlook.scenarios) || outlook.scenarios.length < 1 || outlook.scenarios.length > 5) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'outlook.scenarios must be 1-5 items', subject, arrivalTs } }];
}
for (const s of outlook.scenarios) {
  if (s.probability < 0 || s.probability > 100) {
    return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: `scenario probability out of range: ${s.probability}`, subject, arrivalTs } }];
  }
  if (s.range_low > s.range_high) {
    return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: `range_low > range_high in scenario: ${s.name}`, subject, arrivalTs } }];
  }
}

// Default v2 fields to null/[] if ChatGPT ever omits them, mirroring normalizeBriefing.
meta.sources = Array.isArray(meta.sources) ? meta.sources : [];
summary.macro = summary.macro || {};
for (const k of ['usd_inr', 'gold', 'india_vix', 'us_10y_yield']) {
  if (summary.macro[k] === undefined) summary.macro[k] = null;
}
summary.global_indices = Array.isArray(summary.global_indices) ? summary.global_indices : [];
deep_dive.summary_takeaway = deep_dive.summary_takeaway === undefined ? null : deep_dive.summary_takeaway;

return [{ json: { valid: true, briefing: parsed, date: meta.date, subject, arrivalTs } }];

// Prepare GitHub API calls — encode briefing JSON as base64
const { briefing, date } = items[0].json;
const content = Buffer.from(JSON.stringify(briefing, null, 2)).toString('base64');
return [{ json: { date, content, path: `data/briefings/${date}.json` } }];

// Commit or overwrite briefing file via GitHub API
const { date, content, path } = $node['Prepare Commit Data'].json;
const existingResponse = items[0].json;
const sha = existingResponse?.sha || undefined;

const body = {
  message: `Add briefing for ${date}`,
  content,
  branch: 'main'
};
if (sha) body.sha = sha;

return [{ json: { date, path, body: JSON.stringify(body) } }];

// Update index.json — fetch current, add date if missing, re-commit
const date = $node['Prepare Commit Data'].json.date;

// Fetch current index.json
let indexSha = null;
let currentDates = [];
try {
  const indexRes = await $helpers.request({
    method: 'GET',
    url: 'https://api.github.com/repos/bmdeshmukh18/briefing/contents/data/index.json',
    headers: {
      'Authorization': `Bearer ${process.env.GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github.v3+json'
    },
    json: true
  });
  indexSha = indexRes.sha;
  currentDates = JSON.parse(Buffer.from(indexRes.content, 'base64').toString()).dates || [];
} catch (e) { /* file may not exist yet */ }

if (!currentDates.includes(date)) {
  currentDates = [...currentDates, date].sort();
}

const newContent = Buffer.from(JSON.stringify({ dates: currentDates }, null, 2)).toString('base64');

const body = { message: `Update index for ${date}`, content: newContent, branch: 'main' };
if (indexSha) body.sha = indexSha;

await $helpers.request({
  method: 'PUT',
  url: 'https://api.github.com/repos/bmdeshmukh18/briefing/contents/data/index.json',
  headers: {
    'Authorization': `Bearer ${process.env.GITHUB_TOKEN}`,
    'Content-Type': 'application/json',
    'Accept': 'application/vnd.github.v3+json'
  },
  body: JSON.stringify(body)
});

return [{ json: { success: true, date } }];

// Update history.json — fetch current, upsert row, re-commit
const date = $node['Prepare Commit Data'].json.date;
const briefing = $node['Validate Schema'].json.briefing;

const newRow = {
  date,
  nifty_close: briefing.summary?.nifty50?.close ?? null,
  nifty_change_pct: briefing.summary?.nifty50?.change_pct ?? null,
  fii_net_cr: briefing.summary?.institutional_flows?.fii_net_cr ?? null,
  dii_net_cr: briefing.summary?.institutional_flows?.dii_net_cr ?? null,
  advances: briefing.summary?.breadth?.nifty500_advances ?? null,
  declines: briefing.summary?.breadth?.nifty500_declines ?? null
};

let histSha = null;
let series = [];
try {
  const histRes = await $helpers.request({
    method: 'GET',
    url: 'https://api.github.com/repos/bmdeshmukh18/briefing/contents/data/history.json',
    headers: {
      'Authorization': `Bearer ${process.env.GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github.v3+json'
    },
    json: true
  });
  histSha = histRes.sha;
  series = JSON.parse(Buffer.from(histRes.content, 'base64').toString()).series || [];
} catch (e) { /* file may not exist yet */ }

series = [...series.filter(r => r.date !== date), newRow].sort((a,b) => a.date < b.date ? -1 : 1);

const newContent = Buffer.from(JSON.stringify({ series }, null, 2)).toString('base64');
const body = { message: `Update history for ${date}`, content: newContent, branch: 'main' };
if (histSha) body.sha = histSha;

await $helpers.request({
  method: 'PUT',
  url: 'https://api.github.com/repos/bmdeshmukh18/briefing/contents/data/history.json',
  headers: {
    'Authorization': `Bearer ${process.env.GITHUB_TOKEN}`,
    'Content-Type': 'application/json',
    'Accept': 'application/vnd.github.v3+json'
  },
  body: JSON.stringify(body)
});

return [{ json: { success: true, date } }];

